findings.codeql_raw_query:
/**
 * @name XStream fromXML with untrusted input - unsafe deserialization
 * @description XStream.fromXML() processes XML that can deserialize arbitrary Java objects
 * @kind path-problem
 * @problem.severity error
 * @id java/xstream-unsafe-deserialization
 * @tags security
 *       external/cwe/cwe-502
 */

import java
import semmle.code.java.dataflow.FlowSources
import semmle.code.java.dataflow.TaintTracking

module XStreamDeserConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    exists(MethodCall mc |
      mc.getMethod().hasName("fromXML") and
      mc.getMethod().getDeclaringType().hasQualifiedName("com.thoughtworks.xstream", "XStream") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module XStreamDeserFlow = TaintTracking::Global<XStreamDeserConfig>;
import XStreamDeserFlow::PathGraph

from XStreamDeserFlow::PathNode source, XStreamDeserFlow::PathNode sink
where XStreamDeserFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "XStream deserialization of untrusted data from $@.", source.getNode(), "user input"
